import sys
from functools import lru_cache

def main():
    input_data = sys.stdin.read().split()
    n = int(input_data[0])
    A = list(map(int, input_data[1:n+1]))

    # State: (l, r, last_idx)
    # last_idx = n means -infinity (initial state, no element taken)
    # last_idx = l-1 means last taken was A[l-1] (took from left side)
    # last_idx = r+1 means last taken was A[r+1] (took from right side)
    # Returns True if current player wins

    @lru_cache(maxsize=None)
    def dp(l, r, last_idx):
        if last_idx == n:
            last = -1
        else:
            last = A[last_idx]

        if l > r:
            return False

        can_l = A[l] > last
        can_r = A[r] > last

        if not can_l and not can_r:
            return False

        # Current player wins if any move leads to opponent losing
        if can_l:
            # Take from left: new last = A[l] = A[(l+1)-1], so last_idx = l
            if not dp(l + 1, r, l):
                return True

        if can_r:
            # Take from right: new last = A[r] = A[(r-1)+1], so last_idx = r
            if not dp(l, r - 1, r):
                return True

        return False

    # Initial state: full array, last = -infinity encoded as index n
    if dp(0, n - 1, n):
        print("Alice")
    else:
        print("Bob")

main()

